   //
   //   CR - 1 u>= (1 << BitWidth) - 1.
   APInt IntMax = APInt::getSignMask(BitWidth) - 1;
+  // Now check that the ctlz intrinsic's output is not poison for any value in
+  // the condition false range. The intrinsic may have a range attribute that
+  // restricts its output; if the output range includes values outside that
+  // attribute, those are poison.
+  auto *CtlzInst = dyn_cast<IntrinsicInst>(Ctlz);
+  if (CtlzInst) {
+    ConstantRange CtlzRange = ConstantRange::ctlz(CR, /*ZeroIsPoison=*/false);
+    std::optional<ConstantRange> AttrRange = CtlzInst->getRange();
+    if (AttrRange) {
+      // If the computed range for ctlz output is not a subset of the allowed
+      // range, then there exists a value in the condition false range that
+      // makes ctlz poison, and the transformation is unsafe.
+      if (!CtlzRange.isSubsetOf(*AttrRange))
+        return false;
+    }
+  }
   CR = CR.sub(APInt(BitWidth, 1));
